(new WOW).init();var CONTACTUS={init:function(){$.getJSON("https://api.ipify.org/?format=json",function(i){$.get("http://ipinfo.io/"+i.ip,function(i){$("#countries").val(i.country).trigger("change")},"jsonp")}),CONTACTUS.events.countryChange()},build:{office_details:function(i){var e="";return e+'<div class="office">'+'<div class="marker">'+'<i class="fa fa-map-marker-alt"></i>'+"</div>"+'<div class="office-details">'+('<div class="office-name">'+i.name+"</div>")+('<div class="office-address">'+i.address+"</div>")+('<div class="office-contact">Tel: '+i.contact_number+"</div>")+('<div class="office-email">Email: '+i.email+"</div>")+"</div>"+"</div>"}},events:{countryChange:function(){$("#countries").change(function(){var i=$(this).val(),e="";if(void 0!==OFFICES_JSON[i]&&0<OFFICES_JSON[i].length)for(var a=0;a<OFFICES_JSON[i].length;a++)e+=CONTACTUS.build.office_details(OFFICES_JSON[i][a]);$("#offices").html(e)})}}};$(document).ready(CONTACTUS.init);